class Solution:
    def minimizedStringLength(self, s: str) -> int:
        mask = 0
        for ch in s:
            mask |= 1 << (ord(ch) - ord('a'))
        count = 0
        while mask:
            count += mask & 1
            mask >>= 1
        return count

